ac:structured-macro.ac:plain-text-body:
name: brands-api
octopus: { space: DevOps, group: brands }        # group -> K8s namespace
git:
  repository: brands-api
  version: 1.1266
  image: 064859874041.dkr.ecr.us-east-2.amazonaws.com/usxpress/brands-api:1.1266
  language: go                                    # used for OTel auto-instrument
tags: { owner: enterprise, team: enterprise, purpose: api }
infrastructure:                                   # each key -> a module that runs
  kafka: { ... }
  postgres: { ... }
  iam: { policy: [ { effect: Allow, actions: [s3:GetObject], resources: [...] } ] }
api:                                              # exactly ONE of api|cron|handler|ui
  service: { targetPort: 8080 }
  configVars: { LOG_LEVEL: info }
